import React, {
  useState
} from "react";

import axios from "axios";
import Api from "../api/Api";

function Login() {

  const [mobile, setMobile] =
    useState("");

  const [otp, setOtp] =
    useState("");

  const [showOtp,
    setShowOtp] =
    useState(false);

  const sendOtp = async () => {

    try {

      const res =
        await axios.post(
          Api.send_otp,
          { mobile }
        );

      alert(res.data.message);

      setShowOtp(true);

    } catch (error) {

      alert(
        error.response?.data?.message
      );

    }

  };

  const verifyOtp = async () => {

    try {

      const res =
        await axios.post(
          Api.verify_otp,
          {
            mobile,
            otp,
          }
        );

      localStorage.setItem(
        "token",
        res.data.token
      );

      localStorage.setItem(
        "role",
        res.data.role
      );

      if (
        res.data.role ===
        "driver"
      ) {
        window.location =
          "/driver-dashboard";
      }

      else if (
        res.data.role ===
        "supervisor"
      ) {
        window.location =
          "/supervisor-dashboard";
      }

    } catch (error) {

      alert(
        error.response?.data?.message
      );

    }

  };

  return (
    <div>

      <input
        placeholder="Mobile"
        value={mobile}
        onChange={(e)=>
          setMobile(
            e.target.value
          )
        }
      />

      {!showOtp && (
        <button
          onClick={sendOtp}
        >
          Send OTP
        </button>
      )}

      {showOtp && (
        <>
          <input
            placeholder="OTP"
            value={otp}
            onChange={(e)=>
              setOtp(
                e.target.value
              )
            }
          />

          <button
            onClick={
              verifyOtp
            }
          >
            Login
          </button>
        </>
      )}

    </div>
  );
}

export default Login;
